class UserRegistry {
    private val users = mutableMapOf<Int, String>()

    fun addUser(id: Int, name: String) {
        users[id] = name
    }

    fun getName(id: Int): String? {
        return users[id]
    }

    fun getNameOrDefault(id: Int): String {
        return users[id] ?: "Unknown"
    }
}

