class OrderBook {
    data class Order(
        val item: String,
        val quantity: Int,
        val price: Double
    )

    fun totalValueAbove(orders: List<Order>, minQuantity: Int): Double {
        return orders
            .filter { it.quantity > minQuantity }
            .sumOf { it.price * it.quantity }
    }
}

