data class OrderBook {
    data class Order(
        val item: String,
        val quantity: Int,
        val price: Double
    )

    // Total value of all orders with quantity above the given threshold.
    fun totalValueAbove(orders: List<Order>, minQuantity: Int): Double {
        var total = 0.0
        for (o in orders) {
            if (o.quantity > minQuantity) {
                total += o.price * o.quantity
            }
        }
        return total
    }
}

